// Tax4Us Social Media Agent - Input Processing
const input = $input.first().json;

// Validate required fields
const required = ['platform', 'content_type', 'topic'];
const missing = required.filter(field => !input[field]);
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

// Process social media request
const socialData = {
  platform: input.platform, // 'facebook' or 'linkedin'
  contentType: input.content_type || 'post',
  topic: input.topic,
  targetAudience: input.targetAudience || 'Israeli business owners',
  language: input.language || 'hebrew',
  tone: input.tone || 'professional',
  hashtags: input.hashtags || [],
  timestamp: new Date().toISOString(),
  status: 'processing'
};

return {
  json: {
    ...socialData,
    message: 'Social media request processed successfully',
    nextStep: 'content_generation'
  }
};

parameters.prompt:
Create engaging social media content for Tax4Us based on the following specifications:

Platform: {{ $json.platform }}
Content Type: {{ $json.contentType }}
Topic: {{ $json.topic }}
Target Audience: {{ $json.targetAudience }}
Language: {{ $json.language }}
Tone: {{ $json.tone }}

Requirements:
1. Create platform-specific content (Facebook: casual, LinkedIn: professional)
2. Include relevant hashtags
3. Add call-to-action for Tax4Us services
4. Keep within platform character limits
5. Use appropriate tone and style
6. Include emojis where appropriate
7. Make it engaging and shareable

Format the output with the content and suggested hashtags.

Create an image prompt for an AI image generation tool to create a visual for this social media post:

Platform: {{ $json.platform }}
Topic: {{ $json.topic }}
Content: {{ $('Generate Social Media Content').item.json.text }}

Requirements:
1. Create a professional, business-focused image
2. Include relevant visual elements
3. Use appropriate colors and style
4. Make it engaging and relevant
5. Specify aspect ratio for {{ $json.platform }}
6. Include brand elements if applicable

Return only the image prompt text.

